SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

DROP TRIGGER IF EXISTS tbiu_sc_mem_m_membership_regis ON sc_mem_m_membership_registered CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_mem_m_membership_regis() RETURNS trigger AS $BODY$
declare
  ls_lastdocno_mem sc_mem_edit_name.doc_edit%type;
  ls_year_mem char(4);
  ls_lastdocno_group sc_mem_edit_name.doc_edit%type;
  ls_year_mem_group char(4);
  ls_docno_name sc_mem_edit_name.doc_edit%type;
  ls_docno_group sc_mem_edit_group.doc_edit%type;
BEGIN
--return ;
  if coalesce(NEW.membership_no::text, '') = '' or NEW.membership_no = ' ' then
    CALL spa_dberrcol('sc_mem_m_membership_registered','membership_no',NEW.membership_no);
  end if;

  if coalesce(NEW.application_form_no::text, '') = '' then
    NEW.application_form_no := 'CNV';
  end if;

  if coalesce(NEW.prename_code::text, '') = '' then
    NEW.prename_code := '000';
  end if;

  if coalesce(NEW.member_status_code::text, '') = ''  or NEW.member_status_code = ' '  then
    NEW.member_status_code := '0';
  end if;

  if ( NEW.sex not in ('M','F')) then
    NEW.sex := null;
  end if;

  if coalesce(NEW.nationality_code::text, '') = '' or NEW.nationality_code = ' ' then
    NEW.nationality_code := '01';-- 01 = สัญญาติไทย
  end if;

  if coalesce(NEW.graduate_code::text, '') = '' or NEW.graduate_code = ' ' then
    NEW.graduate_code := '00';
  end if;

  if coalesce(NEW.marriage_status::text, '') = '' or NEW.marriage_status = ' ' then
    NEW.marriage_status := '0';
  end if;

  if coalesce(NEW.drop_loanemer_status::text, '') = '' or NEW.drop_loanemer_status = ' ' then
    NEW.drop_loanemer_status := '0';
  end if;

  if coalesce(NEW.drop_loanspec_status::text, '') = '' or NEW.drop_loanspec_status = ' ' then
    NEW.drop_loanspec_status := '0';
  end if;

  if coalesce(NEW.drop_loannormal_status::text, '') = '' or NEW.drop_loannormal_status = ' ' then
    NEW.drop_loannormal_status := '0';
  end if;

  if coalesce(NEW.collactelral_status::text, '') = '' or NEW.collactelral_status = ' ' then
    NEW.collactelral_status := '0';
  end if;

  if coalesce(NEW.total_loan_int::text, '') = '' then
    NEW.total_loan_int := 0;
  end if;

  if coalesce(NEW.emer_loan_int::text, '') = '' then
    NEW.emer_loan_int := 0;
  end if;

  if coalesce(NEW.norm_loan_int::text, '') = '' then
    NEW.norm_loan_int := 0;
  end if;

  if coalesce(NEW.spec_loan_int::text, '') = '' then
    NEW.spec_loan_int := 0;
  end if;

  -- ดอกเบี้ยสะสม
  --if :new.total_loan_int <> :new.emer_loan_int + :new.norm_loan_int + :new.spec_loan_int then
    --spa_dberrcol('sc_mem_m_membership_registered','total_loan_int',:new.total_loan_int||' ดอกเบี้ยสะสมรวม ไม่เท่ากับดอกเบี้ยแต่ปละกลุ่มเงินกู้รวมกัน(emer_loan_int + norm_loan_int + spec_loan_int)');
  --end if;
  if coalesce(NEW.mem_type::text, '') = '' or NEW.mem_type = ' ' then
    NEW.mem_type := '01';--'01';-- ปกติ
  end if;

  if coalesce(NEW.other_loan::text, '') = '' then
    NEW.other_loan := 0;
  end if;

  if coalesce(NEW.debtor_code::text, '') = '' or NEW.debtor_code = ' ' then
    NEW.debtor_code := '00';
  end if;

  if coalesce(NEW.att_loan_permit::text, '') = '' or NEW.att_loan_permit = ' 'then
    NEW.att_loan_permit := '0';
  end if;

  if coalesce(NEW.app_type::text, '') = '' or NEW.app_type = ' 'then
    NEW.app_type := '0';
  end if;

  --Niorn 2022-02-03 Amnat พี่ใช้ other_code เป็น Grade สมาชิก
  if coalesce(NEW.other_code::text, '') = '' or NEW.other_code = ' ' then
    NEW.other_code := '00';
  end if;

  if coalesce(NEW.other_status::text, '') = '' or NEW.other_status = ' ' then
    NEW.other_status := '00';
  end if;

  if coalesce(NEW.shareloan_code::text, '') = '' or NEW.shareloan_code = ' ' then
    NEW.shareloan_code := '00';
  end if;

  if coalesce(NEW.other_saving_member::text, '') = '' or NEW.other_saving_member = ' 'then
    NEW.other_saving_member := '0';
  end if;

  if coalesce(NEW.branch_id::text, '') = '' or NEW.branch_id = ' ' then
    NEW.branch_id := '01';--'01';
  end if;

  if coalesce(NEW.blood_code::text, '') = '' or NEW.blood_code = ' ' then
    NEW.blood_code := '00';
  end if;

  if coalesce(NEW.drop_chgsharemonth_status::text, '') = '' or NEW.drop_chgsharemonth_status = ' ' then
    NEW.drop_chgsharemonth_status := '0';
  end if;

  if coalesce(NEW.drop_chgloanmonth_status::text, '') = '' or NEW.drop_chgloanmonth_status = ' 'then
    NEW.drop_chgloanmonth_status := '0';
  end if;

  if coalesce(NEW.dead_status::text, '') = '' or NEW.dead_status = ' ' then
    NEW.dead_status := '0';
  end if;

  if coalesce(NEW.force_keeping::text, '') = '' or NEW.force_keeping = ' ' then
    NEW.force_keeping := '0';
  end if;

--  if :new.share_sequester is null or :new.share_sequester = ' ' then
--    :new.share_sequester := '0';
--  end if;
  if coalesce(NEW.adj_payroll::text, '') = '' or NEW.adj_payroll = ' ' then
    NEW.adj_payroll := '0';
  end if;


  if coalesce(NEW.doc_place_status::text, '') = '' or NEW.doc_place_status = ' ' or NEW.doc_place_status = '00' then
    NEW.doc_place_status := '02'; --ที่อยู่ปัจจุบัน
  end if;

    -- null = เงินฝาก/เงินสด
  if coalesce(NEW.method_recieve_dividend::text, '') = '' or NEW.method_recieve_dividend  = ' ' then
    --Niorn 2022-01-30 Amnant  --ถ้าเป็นสมทบ Default โอนเข้าบัญชีสมาชิกหลัก
    if NEW.mem_type = '02' and pka.isCoop('AMN') = '1' then
      NEW.method_recieve_dividend := 'STB';
    else
      NEW.method_recieve_dividend := 'CSH';
    end if;
  end if;

  if coalesce(NEW.dividend_at_resign::text, '') = '' or NEW.dividend_at_resign = ' 'then
    NEW.dividend_at_resign := '0';
  end if;
  if coalesce(NEW.resign_code::text, '') = '' or NEW.resign_code = ' ' then
    NEW.resign_code := '00';
  end if;
  if coalesce(NEW.crem_status::text, '') = '' or NEW.crem_status = ' ' then
    NEW.crem_status :='0';
  end if;
--  if :new.lose_send_share is null or :new.lose_send_share = ' ' then 
--    :new.lose_send_share := '0' ;
--  end if;
  if coalesce(NEW.seize_divident::text, '') = '' or NEW.seize_divident = ' ' then
    NEW.seize_divident := '0';
  end if;
  if coalesce(NEW.seize_average::text, '') = '' or NEW.seize_average = ' ' then
    NEW.seize_average := '0';
  end if;
  if coalesce(NEW.drop_divident::text, '') = '' or NEW.drop_divident = ' ' then
    NEW.drop_divident := '0';
  end if;
  if coalesce(NEW.drop_average::text, '') = '' or NEW.drop_average = ' ' then
    NEW.drop_average := '0';
  end if;

  --แก้ไข คำนำ ชื่อ สกุล
  if ( (OLD.prename_code IS NOT NULL AND OLD.prename_code::text <> '') and NEW.prename_code <> OLD.prename_code )
    or ( (OLD.member_name IS NOT NULL AND OLD.member_name::text <> '') and NEW.member_name <> OLD.member_name )
    or ( (OLD.member_surname IS NOT NULL AND OLD.member_surname::text <> '') and NEW.member_surname <> OLD.member_surname )
    or ( (OLD.date_of_birth IS NOT NULL AND OLD.date_of_birth::text <> '') and NEW.date_of_birth <> OLD.date_of_birth)
  then

    CALL pka_com_docno.sp_generate('EDIT_MEM',ls_lastdocno_mem,ls_year_mem);
    ls_docno_name := substr(ls_year_mem,3,2)||trim(both ls_lastdocno_mem);

    --insert  sc_mem_edit_name
    INSERT INTO sc_mem_edit_name( membership_no,           entry_date,             entry_id,
             operate_date,                
             pre_prename_code,          pre_member_name,         pre_member_surname,          
             prename_code,              member_name,             member_surname,
             entry_br,                  doc_edit 
             ,pre_date_of_birth,        date_of_birth)  
    VALUES ( NEW.membership_no,        statement_timestamp(),               current_setting('app.login_id', true),   
             TO_DATE( statement_timestamp() ),              
             OLD.prename_code,         OLD.member_name,     OLD.member_surname,  
             NEW.prename_code,         NEW.member_name,     NEW.member_surname,
             current_setting('app.login_br', true),    ls_docno_name
             ,OLD.date_of_birth,       NEW.date_of_birth 
             ) 
;
  end if;

   --แก้ไข หน่วย
  if ( (OLD.member_group_no IS NOT NULL AND OLD.member_group_no::text <> '') and NEW.member_group_no <> OLD.member_group_no   )   then
    --insert  sc_mem_edit_group
   INSERT INTO sc_mem_edit_group( membership_no,           entry_date,             entry_id,   
           operate_date,                
           pre_member_group_no,       
           member_group_no,           entry_br )  
  VALUES ( NEW.membership_no,        statement_timestamp(),               current_setting('app.login_id', true),   
           TO_DATE( statement_timestamp() ),              
           OLD.member_group_no,        
           NEW.member_group_no,      current_setting('app.login_br', true)        
           ) 
;
  end if;

  if coalesce(NEW.election_group::text, '') = '' or NEW.election_group = ' ' then
    NEW.election_group := '090000'; --090000
  end if;
  --แก้ไขหน่วยเลือกตั้ง
  --if  1=2 and ( :old.election_group  is not null and :new.election_group <> :old.election_group   )   then 
  if ( (OLD.election_group IS NOT NULL AND OLD.election_group::text <> '') and NEW.election_group <> OLD.election_group   )   then 
    --insert  sc_mem_edit_election
   INSERT INTO sc_mem_edit_election( membership_no,           entry_date,             entry_id,   
           operate_date,                
           pre_election_group,       
           election_group,           entry_br )  
  VALUES ( NEW.membership_no,        statement_timestamp(),               current_setting('app.login_id', true),   
           TO_DATE( statement_timestamp() ),              
           OLD.election_group,        
           NEW.election_group,      current_setting('app.login_br', true)        
           ) 
;
  end if;
  
    --แก้ไขวิธีรับปันผล
  if ( (OLD.method_recieve_dividend IS NOT NULL AND OLD.method_recieve_dividend::text <> '') and NEW.method_recieve_dividend <> OLD.method_recieve_dividend   )   then 
    --insert  sc_mem_edit_recieve_dividend
    INSERT INTO sc_mem_edit_recieve_dividend(    membership_no ,                     entry_date ,            entry_id ,           
           
                operate_date ,                
                
                pre_method_recieve_dividend ,       method_recieve_dividend ,           entry_br 
           )  
    VALUES (    NEW.membership_no ,                statement_timestamp() ,                current_setting('app.login_id', true) ,       
    
                TO_DATE( statement_timestamp() ),          
                
                OLD.method_recieve_dividend ,      NEW.method_recieve_dividend ,      current_setting('app.login_br', true)        
           ) 
;
  end if;

RETURN NEW;
end
$BODY$
 LANGUAGE 'plpgsql' SECURITY DEFINER;
-- REVOKE ALL ON FUNCTION trigger_fct_tbiu_sc_mem_m_membership_regis() FROM PUBLIC;

CREATE TRIGGER tbiu_sc_mem_m_membership_regis
	BEFORE INSERT OR UPDATE ON sc_mem_m_membership_registered FOR EACH ROW
	EXECUTE PROCEDURE trigger_fct_tbiu_sc_mem_m_membership_regis();

